class Solution:
    def numberOfWeakCharacters(self, properties):
        n = len(properties)
        count = 0
        for i in range(n):
            for j in range(n):
                if i != j and properties[j][0] > properties[i][0] and properties[j][1] > properties[i][1]:
                    count += 1
                    break
        return count

