class Solution:
    def numberOfWeakCharacters(self, properties):
        properties.sort(key=lambda x: (-x[0], x[1]))
        max_def = 0
        count = 0
        for atk, df in properties:
            if df < max_def:
                count += 1
            else:
                max_def = df
        return count

