var numberOfWeakCharacters = function(properties) {
    const sorted = properties.slice().sort((a, b) => a[0] !== b[0] ? b[0] - a[0] : a[1] - b[1]);
    let maxDef = 0;
    let count = 0;
    for (const [, df] of sorted) {
        if (df < maxDef) {
            count++;
        } else {
            maxDef = df;
        }
    }
    return count;
};
